.message-input {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 10px 14px;
    font-size: 0.9rem;
    font-family: inherit;
    min-height: 40px;
    max-height: 120px;
    outline: none;
    transition: border-color 0.2s;
