.message-input:focus {
    border-color: #1264a3;
}

.send-btn {
    padding: 10px 20px;
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 8px;
    font-weight: 600;
    font-size: 0.85rem;
    cursor: pointer;
    transition: background 0.15s;
