namespace sv_94778cebd8e04c3d851a6e078466990d.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@using sv_94778cebd8e04c3d851a6e078466990d.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* Left Sidebar - Channel List *@
    <aside class="chat-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (channels is not null)
            {
                @foreach (var channel in channels)
                {
                    <li class="channel-item @(channel.Id == activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name"># @channel.Name</div>
                        <div class="channel-description">@TruncateDescription(channel.Description)</div>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* Main Message Area *@
    <main class="chat-main @(threadOpen ? "thread-open" : "")">
        @if (activeChannel is not null)
        {
            <div class="main-header">
                <h2># @activeChannel.Name</h2>
                <p>@activeChannel.Description</p>
            </div>

            <div class="message-list" @onscroll="OnMessageListScroll" @ref="messageListRef">
                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages...</div>
                }
                @if (messages is not null)
                {
                    @foreach (var message in messages)
                    {
                        <div class="message-item" @onmouseenter="() => hoveredMessageId = message.Id"
                             @onmouseleave="() => hoveredMessageId = null">
                            <div class="message-header">
                                <span class="message-author">@message.Author</span>
                                <span class="message-time">@FormatRelativeTime(message.SentAt)</span>
                            </div>
                            <div class="message-content">@message.Content</div>

                            @if (message.Reactions.Count > 0)
                            {
                                <div class="message-reactions">
                                    @foreach (var reaction in message.Reactions)
                                    {
                                        <span class="reaction-badge" @onclick="() => AddReactionAsync(message.Id, reaction.Emoji)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </span>
                                    }
                                </div>
                            }

                            @if (threadSummaries.TryGetValue(message.Id, out var summary))
                            {
                                <div class="thread-link" @onclick="() => OpenThreadAsync(message)">
                                    @summary.ReplyCount replies
                                </div>
                            }

                            @if (hoveredMessageId == message.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" @onclick="() => OpenThreadAsync(message)" title="Reply">
                                        💬 Reply
                                    </button>
                                    <button class="action-btn" @onclick="() => ToggleEmojiPicker(message.Id)" title="React">
                                        😀 React
                                    </button>
                                </div>

                                @if (emojiPickerMessageId == message.Id)
                                {
                                    <div class="emoji-picker">
                                        @foreach (var emoji in commonEmojis)
                                        {
                                            <button class="emoji-btn" @onclick="() => AddReactionAsync(message.Id, emoji)">
                                                @emoji
                                            </button>
                                        }
                                    </div>
                                }
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" @bind="newMessageContent" @bind:event="oninput"
                          placeholder="Type a message..." @onkeydown="OnMessageKeyDown"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(newMessageContent)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </main>

    @* Right Panel - Thread View *@
    @if (threadOpen && threadRootMessage is not null)
    {
        <aside class="chat-thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-thread-btn" @onclick="CloseThread">✕</button>
            </div>
            <div class="thread-root-message">
                <div class="message-header">
                    <span class="message-author">@threadRootMessage.Author</span>
                    <span class="message-time">@FormatRelativeTime(threadRootMessage.SentAt)</span>
                </div>
                <div class="message-content">@threadRootMessage.Content</div>
            </div>
            <div class="thread-replies">
                @if (threadMessages is not null)
                {
                    @foreach (var reply in threadMessages)
                    {
                        <div class="message-item">
                            <div class="message-header">
                                <span class="message-author">@reply.Author</span>
                                <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>
                        </div>
                    }
                }
            </div>
            <div class="message-input-area">
                <textarea class="message-input" @bind="threadReplyContent" @bind:event="oninput"
                          placeholder="Reply in thread..." @onkeydown="OnThreadKeyDown"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync" disabled="@string.IsNullOrWhiteSpace(threadReplyContent)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private List<Channel>? channels;
    private List<Message>? messages;
    private List<Message>? threadMessages;
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private Channel? activeChannel;
    private int activeChannelId;
    private Message? threadRootMessage;
    private bool threadOpen;
    private string newMessageContent = string.Empty;
    private string threadReplyContent = string.Empty;
    private int? hoveredMessageId;
    private int? emojiPickerMessageId;
    private bool isLoadingMore;
    private int messageSkip;
    private const int PageSize = 30;
    private ElementReference messageListRef;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0]);
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        activeChannel = channel;
        activeChannelId = channel.Id;
        messageSkip = 0;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messageSkip = messages.Count;
        await ChatService.MarkChannelReadAsync(channel.Id);
        await BuildThreadSummaries();
        CloseThread();
        StateHasChanged();
    }

    private async Task BuildThreadSummaries()
    {
        threadSummaries.Clear();
        if (messages is null) return;

        // Identify messages that have replies (messages whose Id is referenced by ReplyToId)
        var rootIds = messages
            .Where(m => m.ReplyToId.HasValue)
            .Select(m => m.ReplyToId!.Value)
            .Distinct()
            .ToHashSet();

        foreach (var rootId in rootIds)
        {
            var replies = messages.Where(m => m.ReplyToId == rootId).ToList();
            if (replies.Count > 0)
            {
                threadSummaries[rootId] = new ThreadSummary(rootId, replies.Count, replies.Max(r => r.SentAt));
            }
        }
    }

    private async Task OnMessageListScroll()
    {
        // Pagination is triggered via JS interop in production; simplified here
    }

    public async Task LoadOlderMessagesAsync()
    {
        if (activeChannel is null || isLoadingMore) return;
        isLoadingMore = true;
        StateHasChanged();

        var olderMessages = await ChatService.GetMessagesAsync(activeChannel.Id, messageSkip, PageSize);
        if (olderMessages.Count > 0)
        {
            messages = olderMessages.Concat(messages ?? []).ToList();
            messageSkip += olderMessages.Count;
            await BuildThreadSummaries();
        }

        isLoadingMore = false;
        StateHasChanged();
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageContent) || activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannel.Id, newMessageContent.Trim(), null);
        messages ??= [];
        messages.Add(sent);
        messageSkip++;
        newMessageContent = string.Empty;
        StateHasChanged();
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessageAsync();
        }
    }

    private async Task OpenThreadAsync(Message rootMessage)
    {
        threadRootMessage = rootMessage;
        threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
        threadOpen = true;
        emojiPickerMessageId = null;
        StateHasChanged();
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadMessages = null;
        threadReplyContent = string.Empty;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyContent) || activeChannel is null || threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannel.Id, threadReplyContent.Trim(), threadRootMessage.Id);
        threadMessages ??= [];
        threadMessages.Add(reply);
        threadReplyContent = string.Empty;
        await BuildThreadSummaries();
        StateHasChanged();
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendThreadReplyAsync();
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Refresh messages to show updated reactions
        if (activeChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(activeChannel.Id, 0, messageSkip);
        }
        StateHasChanged();
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;

        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }

    private static string TruncateDescription(string description)
    {
        return description.Length > 40 ? description[..37] + "..." : description;
    }
}

